from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

def extract_user_claims(token):
    try:
        # Decode the token without verification for development purposes
        decoded_token = jwt.decode(token, options={"verify_signature": False})
        return decoded_token
    except jwt.DecodeError:
        return None

@app.route('/api/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def gateway(path):
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return jsonify({"error": "Authorization header missing"}), 401

    token = auth_header.split(" ")[1]
    user_claims = extract_user_claims(token)
    
    if not user_claims:
        return jsonify({"error": "Invalid token"}), 401

    # Forward the request to the backend service
    # Here you would typically use requests or another library to forward the request
    # For demonstration, we just return the user claims
    return jsonify({"user_claims": user_claims})

if __name__ == '__main__':
    app.run(debug=True)